    public function test_anthropic_stream(): void
    {        $client = \Liter\Llm\LiterLlm::createClient('test-key', getenv('MOCK_SERVER_URL') . '/fixtures/anthropic_stream');
        $request = ChatCompletionRequest::from_json(json_encode(["max_tokens" => 32, "messages" => [["content" => "Count to three, one word per response.", "role" => "user"]], "model" => "anthropic/claude-3-5-sonnet-20241022", "stream" => true]));
