        $this->assertGreaterThanOrEqual(3, count($chunks), 'expected >= 3 chunks');
        $this->assertEquals('One Two Three', implode('', array_map(fn($c) => $c->choices[0]->delta->content ?? '', $chunks)));
        $this->assertTrue(!empty($chunks) && isset(end($chunks)->choices[0]->finish_reason));

    }


